### 2. Incremental Highlighting Algorithm

When text is edited, we don't want to re-tokenize the entire file:

```rust
impl HighlightedBuffer {
    pub fn update_highlighting(&mut self) {
        let Some(dirty_from) = self.dirty_from.take() else { return };
        let Some(tokenizer) = &self.tokenizer else { return };

        // Get state at start of dirty region
        let mut state = if dirty_from == 0 {
            LineState::Normal
        } else {
            self.line_states[dirty_from - 1]
        };

        // Re-tokenize from dirty_from until state matches cached state
        for line_idx in dirty_from..self.buffer.line_count() {
            let line = self.buffer.line(line_idx).unwrap_or("");
            let (tokens, new_state) = tokenizer.tokenize_line(line, state);

            // Update cache
            if line_idx < self.line_tokens.len() {
                self.line_tokens[line_idx] = tokens;

                // Check if we can stop early
                if line_idx < self.line_states.len() 
                   && self.line_states[line_idx] == new_state 
                {
                    // State matches - rest of file is unchanged
                    break;
                }
                self.line_states[line_idx] = new_state;
            } else {
                self.line_tokens.push(tokens);
                self.line_states.push(new_state);
            }

            state = new_state;
        }
    }
}
